SELECT
    day_searched,
    airline,
    source_city,
    destination_city,
    departure_date,
    COUNT(*) AS airline_count,
    ROUND(AVG(total_cost), 2) AS average_cost
FROM staging_flight_observations
WHERE destination_city = 'Tokyo'
    AND TO_CHAR(departure_date, 'MM-DD') = '01-06'
GROUP BY
    day_searched,
    airline,
    source_city,
    destination_city,
    departure_date
ORDER BY day_searched, average_cost DESC;


